const hoy = new Date();
const manana = new Date(hoy);
manana.setDate(hoy.getDate() + 1);
const y = manana.getFullYear();
const m = String(manana.getMonth()+1).padStart(2,'0');
const d = String(manana.getDate()).padStart(2,'0');
const fechaInt = parseInt(`${y}${m}${d}`);
return [{ json: { fechaManannaInt: fechaInt, fechaStr: `${d}/${m}/${y}` } }];

const item = $input.item.json;
const hora = item.Hora || 0;
const hh = String(Math.floor(hora / 100)).padStart(2,'0');
const mm = String(hora % 100).padStart(2,'0');
const fecha = String(item.Fecha);
const fechaStr = `${fecha.substring(6,8)}/${fecha.substring(4,6)}/${fecha.substring(0,4)}`;
const nombre = item.Nombre || 'paciente';
const doctor = 'la clínica';
const mensaje = `👋 Hola ${nombre}, recordamos tu cita *mañana ${fechaStr} a las ${hh}:${mm}h* en ${$vars.CLINICA_NOMBRE}.\n\nResponde *SÍ* para confirmar o *NO* si necesitas cancelar. 🦷`;
return [{ json: { ...item, mensaje, horaStr: `${hh}:${mm}`, fechaStr } }];
